import { useEffect, useState } from 'react';
import { apiRequest } from '../api/client';

export default function LendingsPage() {
  const [lendings, setLendings] = useState([]);
  const [books, setBooks] = useState([]);
  const [members, setMembers] = useState([]);
  const [issue, setIssue] = useState({ bookId: '', memberId: '' });

  const load = async () => {
    setLendings(await apiRequest('/api/lendings'));
    setBooks(await apiRequest('/api/books'));
    setMembers(await apiRequest('/api/members'));
  };

  useEffect(() => { load(); }, []);

  const issueBook = async (e) => {
    e.preventDefault();
    await apiRequest('/api/lendings', {
      method: 'POST',
      body: JSON.stringify({ bookId: Number(issue.bookId), memberId: Number(issue.memberId) })
    });
    setIssue({ bookId: '', memberId: '' });
    await load();
  };

  return (
    <section>
      <h1>Lending Management</h1>
      <form className="card form-grid" onSubmit={issueBook}>
        <h2>Issue Book</h2>
        <select value={issue.bookId} onChange={(e) => setIssue({ ...issue, bookId: e.target.value })} required>
          <option value="">Select Book</option>
          {books.filter((b) => b.availability).map((b) => (
            <option key={b.bookId} value={b.bookId}>{b.title} ({b.isbn})</option>
          ))}
        </select>
        <select value={issue.memberId} onChange={(e) => setIssue({ ...issue, memberId: e.target.value })} required>
          <option value="">Select Member</option>
          {members.map((m) => <option key={m.memberId} value={m.memberId}>{m.name}</option>)}
        </select>
        <button type="submit">Issue</button>
      </form>
      <div className="table-wrap">
        <table>
          <thead>
            <tr><th>Book</th><th>Member</th><th>Issue</th><th>Due</th><th>Return</th><th>Status</th><th>Action</th></tr>
          </thead>
          <tbody>
            {lendings.map((l) => (
              <tr key={l.lendingId}>
                <td>{l.bookTitle}</td><td>{l.memberName}</td>
                <td>{new Date(l.issueDate).toLocaleDateString()}</td>
                <td>{new Date(l.dueDate).toLocaleDateString()}</td>
                <td>{l.returnDate ? new Date(l.returnDate).toLocaleDateString() : '-'}</td>
                <td>{l.overdue ? 'Overdue' : l.returnDate ? 'Returned' : 'Active'}</td>
                <td>
                  {!l.returnDate && (
                    <button onClick={async () => { await apiRequest(`/api/lendings/${l.lendingId}`, { method: 'PUT' }); await load(); }}>
                      Return
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
}

import { useEffect, useState } from 'react';
import { apiRequest } from '../api/client';

export default function NotificationsPage() {
  const [members, setMembers] = useState([]);
  const [form, setForm] = useState({ memberId: '', message: '', overdue: false });

  useEffect(() => {
    apiRequest('/api/members').then(setMembers);
  }, []);

  const send = async (e) => {
    e.preventDefault();
    await apiRequest('/api/notifications', {
      method: 'POST',
      body: JSON.stringify({
        memberId: Number(form.memberId),
        message: form.message,
        overdue: form.overdue
      })
    });
    setForm({ memberId: '', message: '', overdue: false });
    alert('Notification sent');
  };

  return (
    <section>
      <h1>Send Notification</h1>
      <form className="card form-grid" onSubmit={send}>
        <select value={form.memberId} onChange={(e) => setForm({ ...form, memberId: e.target.value })} required>
          <option value="">Select Member</option>
          {members.map((m) => <option key={m.memberId} value={m.memberId}>{m.name}</option>)}
        </select>
        <textarea placeholder="Message" value={form.message} onChange={(e) => setForm({ ...form, message: e.target.value })} required />
        <label>
          <input type="checkbox" checked={form.overdue} onChange={(e) => setForm({ ...form, overdue: e.target.checked })} />
          Overdue
        </label>
        <button type="submit">Send</button>
      </form>
    </section>
  );
}

import { useEffect, useState } from 'react';
import { apiRequest } from '../api/client';

export default function MyLendingsPage() {
  const [lendings, setLendings] = useState([]);

  useEffect(() => {
    apiRequest('/api/lendings/my').then(setLendings);
  }, []);

  return (
    <section>
      <h1>My Lending History</h1>
      <div className="table-wrap">
        <table>
          <thead><tr><th>Book</th><th>Issue</th><th>Due</th><th>Return</th><th>Status</th></tr></thead>
          <tbody>
            {lendings.map((l) => (
              <tr key={l.lendingId}>
                <td>{l.bookTitle}</td>
                <td>{new Date(l.issueDate).toLocaleDateString()}</td>
                <td>{new Date(l.dueDate).toLocaleDateString()}</td>
                <td>{l.returnDate ? new Date(l.returnDate).toLocaleDateString() : '-'}</td>
                <td>{l.overdue ? 'Overdue' : l.returnDate ? 'Returned' : 'Active'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
}

import { useEffect, useState } from 'react';
import { apiRequest } from '../api/client';

export default function MyNotificationsPage() {
  const [items, setItems] = useState([]);

  useEffect(() => {
    apiRequest('/api/notifications/my').then(setItems);
  }, []);

  return (
    <section>
      <h1>My Notifications</h1>
      <div className="grid-cards">
        {items.map((n) => (
          <article key={n.id} className={`card ${n.overdue ? 'overdue' : ''}`}>
            <p>{n.message}</p>
            <small>{new Date(n.sentAt).toLocaleString()} {n.overdue ? '• Overdue' : ''}</small>
          </article>
        ))}
        {!items.length && <p>No notifications yet.</p>}
      </div>
    </section>
  );
}

:root {
  --bg: #f4f7fb;
  --card: #ffffff;
  --text: #1f2937;
  --primary: #2563eb;
  --danger: #dc2626;
  --border: #dbe3f0;
}

* { box-sizing: border-box; }
body {
  margin: 0;
  font-family: "Segoe UI", Tahoma, sans-serif;
  background: var(--bg);
  color: var(--text);
}

.app-shell { min-height: 100vh; }
.topbar {
  display: flex;
  flex-wrap: wrap;
  gap: 1rem;
  align-items: center;
  justify-content: space-between;
  padding: 1rem 1.5rem;
  background: #0f172a;
  color: #fff;
}
.brand { color: #fff; text-decoration: none; font-weight: 700; }
.nav { display: flex; flex-wrap: wrap; gap: 0.75rem; }
.nav a { color: #cbd5e1; text-decoration: none; }
.nav a.active { color: #fff; border-bottom: 2px solid #60a5fa; }
.user-box { display: flex; gap: 0.75rem; align-items: center; }
.user-box button {
  background: #ef4444;
  border: none;
  color: #fff;
  padding: 0.4rem 0.8rem;
  border-radius: 6px;
  cursor: pointer;
}
.content { padding: 1.5rem; max-width: 1200px; margin: 0 auto; }
.subtitle { color: #64748b; }
.auth-page {
  min-height: 100vh;
  display: grid;
  place-items: center;
  padding: 1rem;
}
.card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 1rem;
  box-shadow: 0 8px 24px rgba(15, 23, 42, 0.06);
}
.auth-page .card { width: min(420px, 100%); display: grid; gap: 0.75rem; }
label { display: grid; gap: 0.35rem; font-size: 0.9rem; }
input, select, textarea, button {
  font: inherit;
  padding: 0.55rem 0.7rem;
  border-radius: 8px;
  border: 1px solid var(--border);
}
button {
  background: var(--primary);
  color: #fff;
  border: none;
  cursor: pointer;
}
.search { width: 100%; max-width: 420px; margin-bottom: 1rem; }
.form-grid { display: grid; gap: 0.75rem; margin-bottom: 1rem; }
.table-wrap { overflow-x: auto; }
table { width: 100%; border-collapse: collapse; background: var(--card); }
th, td { padding: 0.65rem; border-bottom: 1px solid var(--border); text-align: left; }
.actions { display: flex; gap: 0.4rem; }
.grid-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 1rem;
}
.error { color: var(--danger); }
.hint { color: #64748b; font-size: 0.85rem; }
.overdue { border-color: #fecaca; background: #fff1f2; }

@media (max-width: 768px) {
  .topbar { flex-direction: column; align-items: flex-start; }
}

server {
  listen 80;
  server_name localhost;
  root /usr/share/nginx/html;
  index index.html;

  location / {
    try_files $uri /index.html;
  }

  location /api/ {
    proxy_pass http://backend:8080/api/;
  }

  location /actuator/ {
    proxy_pass http://backend:8080/actuator/;
  }
}

